contracts/core/Config.sol.content:
// SPDX-License-Identifier: MIT
pragma solidity ^0.8.20;

import "@openzeppelin/contracts/access/AccessControl.sol";
import "@openzeppelin/contracts/utils/Pausable.sol";

/**
 * @title Config
 * @notice 参数配置管理合约 - 所有可调参数唯一存储
 * @dev 所有修改必须通过 Timelock，并 emit 新旧值
 */
contract Config is AccessControl, Pausable {
    // ==================== 角色定义 ====================
    bytes32 public constant DAO_ROLE = keccak256("DAO_ROLE");
    bytes32 public constant OPERATOR_ROLE = keccak256("OPERATOR_ROLE");
    bytes32 public constant GUARDIAN_ROLE = keccak256("GUARDIAN_ROLE");

    // ==================== 时间常量 ====================
    uint256 public rfqValidityPeriod = 2 hours;              // RFQ有效期
    uint256 public quoteValidityPeriod = 30 minutes;         // 报价有效期
    uint256 public initialFeedDeadline = 10 minutes;         // 初始喂价时限
    uint256 public closingFeedDeadline = 10 minutes;         // 平仓喂价时限
    uint256 public defaultMarginCallDeadline = 12 hours;     // 默认追保截止时间
    uint256 public cryptoMarginCallDeadline = 2 hours;       // 加密货币追保截止时间
    uint256 public settlementArbitrationWindow = 24 hours;   // 平仓结算仲裁窗口
    uint256 public defaultArbitrationWindow = 12 hours;      // 其他场景仲裁窗口

    // ==================== 费率常量 (基点 1 = 0.01%) ====================
    uint256 public creationFee = 1 ether;                    // 建仓手续费：1U
    uint256 public tradingFeeRate = 10;                      // 交易手续费：0.1%
    uint256 public arbitrationFee = 30 ether;                // 仲裁费：30U
    uint256 public nstDiscount = 80;                         // NST折扣：80%

    // ==================== 喂价费用 ====================
    uint256 public feedFee_5_3 = 3 ether;                    // 5-3档：3U
    uint256 public feedFee_7_5 = 5 ether;                    // 7-5档：5U
    uint256 public feedFee_10_7 = 8 ether;                   // 10-7档：8U
    uint256 public feedPlatformShare = 10;                   // 平台抽成：10%
    uint256 public feedFeederShare = 90;                     // 喂价员分配：90%

    // ==================== 保证金参数 ====================
    uint256 public minMarginRate = 1000;                     // 最低保证金率：10%（自由卖方）
    uint256 public seatSellerInitialMargin = 0;              // 席位卖方初始保证金：0

    // ==================== 喂价员参数 ====================
    uint256 public minFeederStake = 100 ether;               // 喂价员最低质押：100U

    // ==================== 限制参数 ====================
    uint256 public maxQuotesPerBuyerOrder = 5;               // 买方单最大报价数
    uint256 public maxQuotesPerSellerOrder = 1;              // 卖方单报价即成交
    uint256 public maxConsecutiveDays = 10;                  // 最大连续天数
    uint256 public defaultDailyLimitPercent = 30;            // 默认单日涨幅阈值
    uint256 public minExerciseDelay = 1;                     // 最小行权延迟T+1
    uint256 public maxExerciseDelay = 5;                     // 最大行权延迟T+5

    // ==================== 积分参数 ====================
    uint256 public pointsMultiplier = 100;                   // 积分倍率：1U = 100分

    // ==================== 资金池分配比例 (基点 100 = 1%) ====================
    uint256 public nodeRewardShare = 500;                    // 节点奖励：5%
    uint256 public tokenBuybackShare = 1000;                 // 代币回购：10%
    uint256 public lpPoolShare = 1000;                       // LP池：10%
    uint256 public teamFundShare = 3000;                     // 团队：30%
    uint256 public foundationShare = 2500;                   // 基金会：25%
    uint256 public daoShare = 1000;                          // DAO：10%
    uint256 public growthNodeShare = 1000;                   // 成长节点：10%

    // ==================== 合约地址 ====================
    address public usdtAddress;
    address public usdcAddress;
    address public nstTokenAddress;
    address public vaultManagerAddress;
    address public optionsCoreAddress;
    address public feedProtocolAddress;
    address public seatManagerAddress;
    address public pointsManagerAddress;

    // ==================== 事件 ====================
    event ParameterUpdated(
        string indexed paramName,
        uint256 oldValue,
        uint256 newValue,
        uint256 timestamp
    );

    event AddressUpdated(
        string indexed paramName,
        address oldAddress,
        address newAddress,
        uint256 timestamp
    );

    // ==================== 构造函数 ====================
    constructor(address _admin) {
        _grantRole(DEFAULT_ADMIN_ROLE, _admin);
        _grantRole(DAO_ROLE, _admin);
        _grantRole(OPERATOR_ROLE, _admin);
        _grantRole(GUARDIAN_ROLE, _admin);
    }

    // ==================== 修改器 ====================
    modifier onlyDAO() {
        require(hasRole(DAO_ROLE, msg.sender), "Config: caller is not DAO");
        _;
    }

    modifier onlyOperator() {
        require(hasRole(OPERATOR_ROLE, msg.sender), "Config: caller is not Operator");
        _;
    }

    modifier onlyGuardian() {
        require(hasRole(GUARDIAN_ROLE, msg.sender), "Config: caller is not Guardian");
        _;
    }

    // ==================== 暂停功能 ====================
    function pause() external onlyGuardian {
        _pause();
    }

    function unpause() external onlyDAO {
        _unpause();
    }

    // ==================== 参数设置函数 ====================
    
    /**
     * @notice 设置 RFQ 有效期
     */
    function setRfqValidityPeriod(uint256 _value) external onlyDAO {
        uint256 oldValue = rfqValidityPeriod;
        rfqValidityPeriod = _value;
        emit ParameterUpdated("rfqValidityPeriod", oldValue, _value, block.timestamp);
    }

    /**
     * @notice 设置报价有效期
     */
    function setQuoteValidityPeriod(uint256 _value) external onlyDAO {
        uint256 oldValue = quoteValidityPeriod;
        quoteValidityPeriod = _value;
        emit ParameterUpdated("quoteValidityPeriod", oldValue, _value, block.timestamp);
    }

    /**
     * @notice 设置建仓手续费
     */
    function setCreationFee(uint256 _value) external onlyDAO {
        uint256 oldValue = creationFee;
        creationFee = _value;
        emit ParameterUpdated("creationFee", oldValue, _value, block.timestamp);
    }

    /**
     * @notice 设置交易手续费率
     */
    function setTradingFeeRate(uint256 _value) external onlyDAO {
        uint256 oldValue = tradingFeeRate;
        tradingFeeRate = _value;
        emit ParameterUpdated("tradingFeeRate", oldValue, _value, block.timestamp);
    }

    /**
     * @notice 设置仲裁费
     */
    function setArbitrationFee(uint256 _value) external onlyDAO {
        uint256 oldValue = arbitrationFee;
        arbitrationFee = _value;
        emit ParameterUpdated("arbitrationFee", oldValue, _value, block.timestamp);
    }

    /**
     * @notice 设置最低保证金率
     */
    function setMinMarginRate(uint256 _value) external onlyDAO {
        uint256 oldValue = minMarginRate;
        minMarginRate = _value;
        emit ParameterUpdated("minMarginRate", oldValue, _value, block.timestamp);
    }

    /**
     * @notice 设置喂价员最低质押
     */
    function setMinFeederStake(uint256 _value) external onlyDAO {
        uint256 oldValue = minFeederStake;
        minFeederStake = _value;
        emit ParameterUpdated("minFeederStake", oldValue, _value, block.timestamp);
    }

    // ==================== 地址设置函数 ====================

    /**
     * @notice 设置 USDT 地址
     */
    function setUsdtAddress(address _address) external onlyDAO {
        address oldAddress = usdtAddress;
        usdtAddress = _address;
        emit AddressUpdated("usdtAddress", oldAddress, _address, block.timestamp);
    }

    /**
     * @notice 设置 VaultManager 地址
     */
    function setVaultManagerAddress(address _address) external onlyDAO {
        address oldAddress = vaultManagerAddress;
        vaultManagerAddress = _address;
        emit AddressUpdated("vaultManagerAddress", oldAddress, _address, block.timestamp);
    }

    /**
     * @notice 设置 OptionsCore 地址
     */
    function setOptionsCoreAddress(address _address) external onlyDAO {
        address oldAddress = optionsCoreAddress;
        optionsCoreAddress = _address;
        emit AddressUpdated("optionsCoreAddress", oldAddress, _address, block.timestamp);
    }

    /**
     * @notice 设置 FeedProtocol 地址
     */
    function setFeedProtocolAddress(address _address) external onlyDAO {
        address oldAddress = feedProtocolAddress;
        feedProtocolAddress = _address;
        emit AddressUpdated("feedProtocolAddress", oldAddress, _address, block.timestamp);
    }

    /**
     * @notice 设置 SeatManager 地址
     */
    function setSeatManagerAddress(address _address) external onlyDAO {
        address oldAddress = seatManagerAddress;
        seatManagerAddress = _address;
        emit AddressUpdated("seatManagerAddress", oldAddress, _address, block.timestamp);
    }

    /**
     * @notice 设置 PointsManager 地址
     */
    function setPointsManagerAddress(address _address) external onlyDAO {
        address oldAddress = pointsManagerAddress;
        pointsManagerAddress = _address;
        emit AddressUpdated("pointsManagerAddress", oldAddress, _address, block.timestamp);
    }

    // ==================== 查询函数 ====================

    /**
     * @notice 获取喂价费用
     * @param tier 喂价档位 (0=5-3, 1=7-5, 2=10-7)
     */
    function getFeedFee(uint8 tier) external view returns (uint256) {
        if (tier == 0) return feedFee_5_3;
        if (tier == 1) return feedFee_7_5;
        if (tier == 2) return feedFee_10_7;
        revert("Config: invalid feed tier");
    }

    /**
     * @notice 获取追保截止时间
     * @param isCrypto 是否为加密货币/外汇
     */
    function getMarginCallDeadline(bool isCrypto) external view returns (uint256) {
        return isCrypto ? cryptoMarginCallDeadline : defaultMarginCallDeadline;
    }

    /**
     * @notice 获取仲裁窗口
     * @param isSettlement 是否为平仓结算
     */
    function getArbitrationWindow(bool isSettlement) external view returns (uint256) {
        return isSettlement ? settlementArbitrationWindow : defaultArbitrationWindow;
    }
}

contracts/core/OptionsCore.sol.content:
// SPDX-License-Identifier: MIT
pragma solidity ^0.8.20;

import "@openzeppelin/contracts/token/ERC20/IERC20.sol";
import "@openzeppelin/contracts/token/ERC20/utils/SafeERC20.sol";
import "@openzeppelin/contracts/access/AccessControl.sol";
import "@openzeppelin/contracts/utils/ReentrancyGuard.sol";
import "@openzeppelin/contracts/utils/Pausable.sol";
import "../libraries/NSTTypes.sol";
import "../interfaces/IOptionsCore.sol";
import "../vault/VaultManager.sol";
import "./Config.sol";

/**
 * @title OptionsCore
 * @notice 期权核心合约 - 订单创建、匹配、结算
 * @dev 继承 IOptionsCore 接口，实现所有核心功能
 */
contract OptionsCore is IOptionsCore, AccessControl, ReentrancyGuard, Pausable {
    using SafeERC20 for IERC20;

    // ==================== 状态变量 ====================
    Config public config;
    VaultManager public vaultManager;
    IERC20 public usdt;

    uint256 public nextOrderId = 1;
    uint256 public nextQuoteId = 1;

    // 订单存储
    mapping(uint256 => Order) public orders;
    mapping(uint256 => Quote[]) public orderQuotes;
    mapping(uint256 => Quote) public quotes;

    // 用户订单索引
    mapping(address => uint256[]) public buyerOrders;
    mapping(address => uint256[]) public sellerOrders;

    // 订单检索索引
    mapping(string => uint256[]) private ordersByCountry;
    mapping(string => uint256[]) private ordersByMarket;
    mapping(string => uint256[]) private ordersByCode;

    // ==================== 构造函数 ====================
    constructor(
        address _config,
        address _vaultManager,
        address _usdt,
        address _admin
    ) {
        config = Config(_config);
        vaultManager = VaultManager(_vaultManager);
        usdt = IERC20(_usdt);
        
        _grantRole(DEFAULT_ADMIN_ROLE, _admin);
    }

    // ==================== 修改器 ====================
    modifier validOrder(uint256 orderId) {
        require(orderId > 0 && orderId < nextOrderId, "OptionsCore: invalid order id");
        _;
    }

    modifier onlyBuyer(uint256 orderId) {
        require(msg.sender == orders[orderId].buyer, "OptionsCore: not buyer");
        _;
    }

    modifier onlySeller(uint256 orderId) {
        require(msg.sender == orders[orderId].seller, "OptionsCore: not seller");
        _;
    }

    modifier inStatus(uint256 orderId, OrderStatus expectedStatus) {
        require(orders[orderId].status == expectedStatus, "OptionsCore: invalid order status");
        _;
    }

    // ==================== 买方功能实现 ====================

    /**
     * @notice 买方创建询价订单
     */
    function createBuyerRFQ(
        string calldata underlyingName,
        string calldata underlyingCode,
        string calldata market,
        string calldata country,
        string calldata refPrice,
        Direction direction,
        uint256 notionalUSDT,
        uint256 expiryTimestamp,
        uint256 maxPremiumRate,
        uint256 minMarginRate,
        SellerType acceptedSellerType,
        address designatedSeller,
        uint256 arbitrationWindow,
        uint256 marginCallDeadline,
        bool dividendAdjustment
    ) external override nonReentrant whenNotPaused returns (uint256 orderId) {
        require(notionalUSDT > 0, "OptionsCore: notional must be positive");
        require(expiryTimestamp > block.timestamp, "OptionsCore: expiry must be in future");
        require(minMarginRate >= config.minMarginRate(), "OptionsCore: margin rate too low");

        // 收取建仓手续费 1U
        usdt.safeTransferFrom(msg.sender, address(vaultManager), config.creationFee());
        
        orderId = nextOrderId++;

        Order storage order = orders[orderId];
        order.orderId = orderId;
        order.buyer = msg.sender;
        order.underlyingName = underlyingName;
        order.underlyingCode = underlyingCode;
        order.market = market;
        order.country = country;
        order.refPrice = refPrice;
        order.direction = direction;
        order.notionalUSDT = notionalUSDT;
        order.expiryTimestamp = expiryTimestamp;
        order.premiumRate = maxPremiumRate;
        order.minMarginRate = minMarginRate;
        order.sellerType = acceptedSellerType;
        order.designatedSeller = designatedSeller;
        order.arbitrationWindow = arbitrationWindow;
        order.marginCallDeadline = marginCallDeadline;
        order.dividendAdjustment = dividendAdjustment;
        order.status = OrderStatus.RFQ_CREATED;
        order.createdAt = block.timestamp;

        // 添加到用户订单列表
        buyerOrders[msg.sender].push(orderId);

        // 添加到检索索引
        ordersByCountry[country].push(orderId);
        ordersByMarket[market].push(orderId);
        ordersByCode[underlyingCode].push(orderId);

        emit OrderCreated(orderId, msg.sender, true, block.timestamp);
        emit OrderStatusChanged(orderId, OrderStatus.RFQ_CREATED, OrderStatus.RFQ_CREATED, "created", block.timestamp);

        return orderId;
    }

    /**
     * @notice 买方选择卖方报价成交
     */
    function acceptQuote(uint256 quoteId) external override nonReentrant whenNotPaused {
        Quote storage quote = quotes[quoteId];
        require(quote.status == QuoteStatus.Active, "OptionsCore: quote not active");
        require(block.timestamp <= quote.expiresAt, "OptionsCore: quote expired");

        Order storage order = orders[quote.orderId];
        require(msg.sender == order.buyer, "OptionsCore: not buyer");
        require(order.status == OrderStatus.RFQ_CREATED || order.status == OrderStatus.QUOTING, "OptionsCore: invalid status");
        require(quote.premiumRate <= order.premiumRate, "OptionsCore: premium rate exceeds max");

        // 更新报价状态
        quote.status = QuoteStatus.Accepted;

        // 更新订单信息
        order.seller = quote.seller;
        order.sellerType = quote.sellerType;
        order.premiumRate = quote.premiumRate;
        order.premiumAmount = quote.premiumAmount;
        order.initialMargin = quote.marginAmount;
        order.currentMargin = quote.marginAmount;
        order.liquidationRule = quote.liquidationRule;
        order.consecutiveDays = quote.consecutiveDays;
        order.dailyLimitPercent = quote.dailyLimitPercent;
        
        OrderStatus oldStatus = order.status;
        order.status = OrderStatus.MATCHED;
        order.matchedAt = block.timestamp;

        // 买方支付期权费 + 交易手续费
        uint256 tradingFee = (order.notionalUSDT * config.tradingFeeRate()) / 10000;
        uint256 totalPayment = quote.premiumAmount + tradingFee;
        usdt.safeTransferFrom(msg.sender, address(vaultManager), totalPayment);

        // 添加到卖方订单列表
        sellerOrders[quote.seller].push(order.orderId);

        // 将其他报价设为拒绝
        Quote[] storage allQuotes = orderQuotes[order.orderId];
        for (uint256 i = 0; i < allQuotes.length; i++) {
            if (allQuotes[i].quoteId != quoteId && allQuotes[i].status == QuoteStatus.Active) {
                allQuotes[i].status = QuoteStatus.Rejected;
            }
        }

        emit OrderMatched(order.orderId, order.buyer, order.seller, block.timestamp);
        emit OrderStatusChanged(order.orderId, oldStatus, OrderStatus.MATCHED, "quote accepted", block.timestamp);
    }

    /**
     * @notice 买方发起喂价请求
     */
    function requestFeed(uint256 orderId, FeedTier tier) external payable override 
        validOrder(orderId) 
        onlyBuyer(orderId) 
        nonReentrant 
        whenNotPaused 
    {
        // 喂价逻辑将在 FeedProtocol 合约中实现
        // 这里只是接口预留
        revert("OptionsCore: feed protocol not implemented yet");
    }

    /**
     * @notice 买方提前行权
     */
    function earlyExercise(uint256 orderId) external override 
        validOrder(orderId) 
        onlyBuyer(orderId) 
        inStatus(orderId, OrderStatus.LIVE) 
        nonReentrant 
        whenNotPaused 
    {
        Order storage order = orders[orderId];
        
        // 检查 T+X 条件
        uint256 requiredDelay = uint256(order.exerciseDelay) * 1 days;
        require(
            block.timestamp >= order.matchedAt + requiredDelay,
            "OptionsCore: exercise delay not met"
        );

        OrderStatus oldStatus = order.status;
        order.status = OrderStatus.WAITING_FINAL_FEED;

        emit OrderStatusChanged(orderId, oldStatus, OrderStatus.WAITING_FINAL_FEED, "early exercise", block.timestamp);
    }

    /**
     * @notice 买方取消未成交的RFQ
     */
    function cancelRFQ(uint256 orderId) external override 
        validOrder(orderId) 
        onlyBuyer(orderId) 
        nonReentrant 
        whenNotPaused 
    {
        Order storage order = orders[orderId];
        require(
            order.status == OrderStatus.RFQ_CREATED || order.status == OrderStatus.QUOTING,
            "OptionsCore: cannot cancel after match"
        );

        OrderStatus oldStatus = order.status;
        order.status = OrderStatus.CANCELLED;

        // 注意：建仓手续费不退还

        emit OrderCancelled(orderId, "buyer cancelled", block.timestamp);
        emit OrderStatusChanged(orderId, oldStatus, OrderStatus.CANCELLED, "buyer cancelled", block.timestamp);
    }

    // ==================== 卖方功能实现 ====================

    /**
     * @notice 卖方创建卖单
     */
    function createSellerOrder(
        string calldata underlyingName,
        string calldata underlyingCode,
        string calldata market,
        string calldata country,
        string calldata refPrice,
        Direction direction,
        uint256 notionalUSDT,
        uint256 expiryTimestamp,
        uint256 premiumRate,
        uint256 marginAmount,
        LiquidationRule liquidationRule,
        uint8 consecutiveDays,
        uint8 dailyLimitPercent,
        uint256 arbitrationWindow,
        bool dividendAdjustment
    ) external override nonReentrant whenNotPaused returns (uint256 orderId) {
        require(notionalUSDT > 0, "OptionsCore: notional must be positive");
        require(expiryTimestamp > block.timestamp, "OptionsCore: expiry must be in future");

        // 收取建仓手续费 1U
        usdt.safeTransferFrom(msg.sender, address(vaultManager), config.creationFee());
        
        // 收取保证金
        if (marginAmount > 0) {
            usdt.safeTransferFrom(msg.sender, address(vaultManager), marginAmount);
        }
        
        orderId = nextOrderId++;

        Order storage order = orders[orderId];
        order.orderId = orderId;
        order.seller = msg.sender;
        order.underlyingName = underlyingName;
        order.underlyingCode = underlyingCode;
        order.market = market;
        order.country = country;
        order.refPrice = refPrice;
        order.direction = direction;
        order.notionalUSDT = notionalUSDT;
        order.expiryTimestamp = expiryTimestamp;
        order.premiumRate = premiumRate;
        order.premiumAmount = (notionalUSDT * premiumRate) / 10000;
        order.initialMargin = marginAmount;
        order.currentMargin = marginAmount;
        order.liquidationRule = liquidationRule;
        order.consecutiveDays = consecutiveDays;
        order.dailyLimitPercent = dailyLimitPercent;
        order.arbitrationWindow = arbitrationWindow;
        order.dividendAdjustment = dividendAdjustment;
        order.status = OrderStatus.RFQ_CREATED;
        order.createdAt = block.timestamp;

        // 添加到卖方订单列表
        sellerOrders[msg.sender].push(orderId);

        // 添加到检索索引
        ordersByCountry[country].push(orderId);
        ordersByMarket[market].push(orderId);
        ordersByCode[underlyingCode].push(orderId);

        emit OrderCreated(orderId, msg.sender, false, block.timestamp);

        return orderId;
    }

    /**
     * @notice 卖方对买方RFQ报价
     */
    function submitQuote(
        uint256 orderId,
        uint256 premiumRate,
        uint256 marginRate,
        LiquidationRule liquidationRule,
        uint8 consecutiveDays,
        uint8 dailyLimitPercent
    ) external override validOrder(orderId) nonReentrant whenNotPaused returns (uint256 quoteId) {
        Order storage order = orders[orderId];
        require(
            order.status == OrderStatus.RFQ_CREATED || order.status == OrderStatus.QUOTING,
            "OptionsCore: order not accepting quotes"
        );
        require(order.buyer != address(0), "OptionsCore: not a buyer order");
        require(block.timestamp < order.createdAt + config.rfqValidityPeriod(), "OptionsCore: RFQ expired");

        // 检查报价数量限制
        require(
            orderQuotes[orderId].length < config.maxQuotesPerBuyerOrder(),
            "OptionsCore: max quotes reached"
        );

        // 检查卖方类型
        if (order.sellerType == SellerType.DesignatedSeller) {
            require(msg.sender == order.designatedSeller, "OptionsCore: not designated seller");
        }

        // 计算保证金金额
        uint256 marginAmount = (order.notionalUSDT * marginRate) / 10000;
        require(marginRate >= order.minMarginRate, "OptionsCore: margin rate too low");

        // 收取保证金
        usdt.safeTransferFrom(msg.sender, address(vaultManager), marginAmount);

        quoteId = nextQuoteId++;

        Quote memory quote = Quote({
            quoteId: quoteId,
            orderId: orderId,
            seller: msg.sender,
            sellerType: SellerType.FreeSeller,  // TODO: 根据实际情况判断
            premiumRate: premiumRate,
            premiumAmount: (order.notionalUSDT * premiumRate) / 10000,
            marginRate: marginRate,
            marginAmount: marginAmount,
            liquidationRule: liquidationRule,
            consecutiveDays: consecutiveDays,
            dailyLimitPercent: dailyLimitPercent,
            createdAt: block.timestamp,
            expiresAt: block.timestamp + config.quoteValidityPeriod(),
            status: QuoteStatus.Active
        });

        quotes[quoteId] = quote;
        orderQuotes[orderId].push(quote);

        // 更新订单状态为报价中
        if (order.status == OrderStatus.RFQ_CREATED) {
            order.status = OrderStatus.QUOTING;
        }

        emit QuoteSubmitted(orderId, quoteId, msg.sender, premiumRate, block.timestamp);

        return quoteId;
    }

    /**
     * @notice 卖方追加保证金
     */
    function addMargin(uint256 orderId, uint256 amount) external override 
        validOrder(orderId) 
        onlySeller(orderId) 
        nonReentrant 
        whenNotPaused 
    {
        require(amount > 0, "OptionsCore: amount must be positive");
        
        Order storage order = orders[orderId];
        require(order.status == OrderStatus.LIVE, "OptionsCore: order not live");

        uint256 oldMargin = order.currentMargin;
        usdt.safeTransferFrom(msg.sender, address(vaultManager), amount);
        order.currentMargin += amount;

        emit MarginChanged(orderId, msg.sender, oldMargin, order.currentMargin, "add", block.timestamp);
    }

    /**
     * @notice 卖方提取超额保证金（不能低于初始保证金）
     */
    function withdrawExcessMargin(uint256 orderId, uint256 amount) external override 
        validOrder(orderId) 
        onlySeller(orderId) 
        nonReentrant 
        whenNotPaused 
    {
        Order storage order = orders[orderId];
        require(order.status == OrderStatus.LIVE, "OptionsCore: order not live");
        
        uint256 excess = order.currentMargin - order.initialMargin;
        require(amount <= excess, "OptionsCore: cannot withdraw below initial margin");

        uint256 oldMargin = order.currentMargin;
        order.currentMargin -= amount;
        
        // 通过 VaultManager 提取
        vaultManager.withdrawMargin(msg.sender, address(usdt), amount);

        emit MarginChanged(orderId, msg.sender, oldMargin, order.currentMargin, "withdraw", block.timestamp);
    }

    /**
     * @notice 到期结算
     * @dev 根据最终喂价与开仓价计算盈亏，划转资金
     */
    function settle(uint256 orderId) external override 
        validOrder(orderId) 
        nonReentrant 
        whenNotPaused 
    {
        Order storage order = orders[orderId];
        require(order.status == OrderStatus.PENDING_SETTLEMENT, "OptionsCore: not pending settlement");
        require(order.lastFeedPrice > 0, "OptionsCore: no feed price");

        // 计算盈亏
        uint256 strikePrice = _parsePrice(order.refPrice);
        uint256 finalPrice = order.lastFeedPrice;
        
        uint256 buyerProfit = 0;
        
        if (order.direction == Direction.Call) {
            // 看涨期权：买方盈利 = max(0, 最终价 - 开仓价) * 名义本金 / 开仓价
            if (finalPrice > strikePrice) {
                buyerProfit = (finalPrice - strikePrice) * order.notionalUSDT / strikePrice;
            }
        } else {
            // 看跌期权：买方盈利 = max(0, 开仓价 - 最终价) * 名义本金 / 开仓价
            if (strikePrice > finalPrice) {
                buyerProfit = (strikePrice - finalPrice) * order.notionalUSDT / strikePrice;
            }
        }

        // 限制盈利不超过卖方保证金
        uint256 buyerPayout = 0;
        uint256 sellerPayout = 0;
        
        if (buyerProfit > 0) {
            // 买方盈利，从卖方保证金中划出
            if (buyerProfit > order.currentMargin) {
                buyerProfit = order.currentMargin; // 最多赔完保证金
            }
            buyerPayout = buyerProfit;
            sellerPayout = order.currentMargin - buyerProfit;
        } else {
            // 买方亏损或平价，卖方拿回全部保证金
            sellerPayout = order.currentMargin;
        }

        // 划转资金
        if (buyerPayout > 0) {
            vaultManager.transferMargin(
                order.seller,
                order.buyer,
                address(usdt),
                buyerPayout,
                "settlement payout"
            );
        }
        
        // 释放剩余保证金给卖方
        if (sellerPayout > 0) {
            vaultManager.withdrawMargin(order.seller, address(usdt), sellerPayout);
        }

        OrderStatus oldStatus = order.status;
        order.status = OrderStatus.SETTLED;
        order.settledAt = block.timestamp;

        emit OrderSettled(orderId, buyerPayout, sellerPayout, block.timestamp);
        emit OrderStatusChanged(orderId, oldStatus, OrderStatus.SETTLED, "settled", block.timestamp);
    }

    /**
     * @notice 解析价格字符串为 uint256 (简化实现，实际需要更复杂的解析)
     */
    function _parsePrice(string memory priceStr) internal pure returns (uint256) {
        bytes memory b = bytes(priceStr);
        uint256 result = 0;
        uint256 decimals = 0;
        bool afterDot = false;
        
        for (uint256 i = 0; i < b.length; i++) {
            if (b[i] == '.') {
                afterDot = true;
                continue;
            }
            if (b[i] >= '0' && b[i] <= '9') {
                result = result * 10 + (uint8(b[i]) - 48);
                if (afterDot) decimals++;
            }
        }
        
        // 标准化到 18 位小数
        if (decimals < 18) {
            result = result * (10 ** (18 - decimals));
        }
        return result;
    }

    /**
     * @notice 发起仲裁
     */
    function initiateArbitration(uint256 orderId) external payable override 
        validOrder(orderId) 
        nonReentrant 
        whenNotPaused 
    {
        Order storage order = orders[orderId];
        require(
            order.status == OrderStatus.PENDING_SETTLEMENT,
            "OptionsCore: cannot initiate arbitration"
        );
        require(
            msg.sender == order.buyer || msg.sender == order.seller,
            "OptionsCore: not party to order"
        );
        require(
            block.timestamp <= order.settledAt + order.arbitrationWindow,
            "OptionsCore: arbitration window closed"
        );

        // 收取仲裁费 30U
        usdt.safeTransferFrom(msg.sender, address(vaultManager), config.arbitrationFee());

        OrderStatus oldStatus = order.status;
        order.status = OrderStatus.ARBITRATION;

        emit OrderStatusChanged(orderId, oldStatus, OrderStatus.ARBITRATION, "arbitration initiated", block.timestamp);
    }

    /**
     * @notice 强制清算（保证金不足）
     */
    function forceLiquidate(uint256 orderId) external override 
        validOrder(orderId) 
        nonReentrant 
        whenNotPaused 
    {
        Order storage order = orders[orderId];
        require(order.status == OrderStatus.LIVE, "OptionsCore: order not live");

        // TODO: 检查保证金是否充足

        OrderStatus oldStatus = order.status;
        order.status = OrderStatus.LIQUIDATED;
        order.settledAt = block.timestamp;

        emit OrderLiquidated(orderId, order.buyer, order.currentMargin, block.timestamp);
        emit OrderStatusChanged(orderId, oldStatus, OrderStatus.LIQUIDATED, "force liquidated", block.timestamp);
    }

    // ==================== 查询功能实现 ====================

    function getOrder(uint256 orderId) external view override returns (Order memory) {
        return orders[orderId];
    }

    function getQuotes(uint256 orderId) external view override returns (Quote[] memory) {
        return orderQuotes[orderId];
    }

    function getBuyerOrders(address buyer) external view override returns (uint256[] memory) {
        return buyerOrders[buyer];
    }

    function getSellerOrders(address seller) external view override returns (uint256[] memory) {
        return sellerOrders[seller];
    }

    /**
     * @notice 按国家检索订单
     */
    function getOrdersByCountry(string calldata country) external view returns (uint256[] memory) {
        return ordersByCountry[country];
    }

    /**
     * @notice 按市场检索订单
     */
    function getOrdersByMarket(string calldata market) external view returns (uint256[] memory) {
        return ordersByMarket[market];
    }

    // ==================== 管理功能 ====================

    function setConfig(address _config) external onlyRole(DEFAULT_ADMIN_ROLE) {
        config = Config(_config);
    }

    function setVaultManager(address _vaultManager) external onlyRole(DEFAULT_ADMIN_ROLE) {
        vaultManager = VaultManager(_vaultManager);
    }

    function pause() external onlyRole(DEFAULT_ADMIN_ROLE) {
        _pause();
    }

    function unpause() external onlyRole(DEFAULT_ADMIN_ROLE) {
        _unpause();
    }
}

contracts/interfaces/IOptionsCore.sol.content:
// SPDX-License-Identifier: MIT
pragma solidity ^0.8.20;

import "../libraries/NSTTypes.sol";

/**
 * @title IOptionsCore
 * @notice 期权核心合约接口
 */
interface IOptionsCore {
    // ==================== 事件 ====================
    event OrderCreated(
        uint256 indexed orderId,
        address indexed creator,
        bool isBuyerOrder,
        uint256 timestamp
    );

    event QuoteSubmitted(
        uint256 indexed orderId,
        uint256 indexed quoteId,
        address indexed seller,
        uint256 premiumRate,
        uint256 timestamp
    );

    event OrderMatched(
        uint256 indexed orderId,
        address indexed buyer,
        address indexed seller,
        uint256 timestamp
    );

    event OrderSettled(
        uint256 indexed orderId,
        uint256 buyerPayout,
        uint256 sellerPayout,
        uint256 timestamp
    );

    event OrderLiquidated(
        uint256 indexed orderId,
        address beneficiary,
        uint256 amount,
        uint256 timestamp
    );

    event OrderCancelled(
        uint256 indexed orderId,
        string reason,
        uint256 timestamp
    );

    event OrderStatusChanged(
        uint256 indexed orderId,
        OrderStatus oldStatus,
        OrderStatus newStatus,
        string reason,
        uint256 timestamp
    );

    event MarginChanged(
        uint256 indexed orderId,
        address indexed seller,
        uint256 oldAmount,
        uint256 newAmount,
        string changeType,
        uint256 timestamp
    );

    // ==================== 买方功能 ====================

    /**
     * @notice 买方创建询价订单
     */
    function createBuyerRFQ(
        string calldata underlyingName,
        string calldata underlyingCode,
        string calldata market,
        string calldata country,
        string calldata refPrice,
        Direction direction,
        uint256 notionalUSDT,
        uint256 expiryTimestamp,
        uint256 maxPremiumRate,
        uint256 minMarginRate,
        SellerType acceptedSellerType,
        address designatedSeller,
        uint256 arbitrationWindow,
        uint256 marginCallDeadline,
        bool dividendAdjustment
    ) external returns (uint256 orderId);

    /**
     * @notice 买方选择卖方报价成交
     */
    function acceptQuote(uint256 quoteId) external;

    /**
     * @notice 买方发起喂价请求
     */
    function requestFeed(uint256 orderId, FeedTier tier) external payable;

    /**
     * @notice 买方提前行权
     */
    function earlyExercise(uint256 orderId) external;

    /**
     * @notice 买方取消未成交的RFQ
     */
    function cancelRFQ(uint256 orderId) external;

    // ==================== 卖方功能 ====================

    /**
     * @notice 卖方创建卖单
     */
    function createSellerOrder(
        string calldata underlyingName,
        string calldata underlyingCode,
        string calldata market,
        string calldata country,
        string calldata refPrice,
        Direction direction,
        uint256 notionalUSDT,
        uint256 expiryTimestamp,
        uint256 premiumRate,
        uint256 marginAmount,
        LiquidationRule liquidationRule,
        uint8 consecutiveDays,
        uint8 dailyLimitPercent,
        uint256 arbitrationWindow,
        bool dividendAdjustment
    ) external returns (uint256 orderId);

    /**
     * @notice 卖方对买方RFQ报价
     */
    function submitQuote(
        uint256 orderId,
        uint256 premiumRate,
        uint256 marginRate,
        LiquidationRule liquidationRule,
        uint8 consecutiveDays,
        uint8 dailyLimitPercent
    ) external returns (uint256 quoteId);

    /**
     * @notice 卖方追加保证金
     */
    function addMargin(uint256 orderId, uint256 amount) external;

    /**
     * @notice 卖方提取超额保证金
     */
    function withdrawExcessMargin(uint256 orderId, uint256 amount) external;

    // ==================== 结算功能 ====================

    /**
     * @notice 到期结算
     */
    function settle(uint256 orderId) external;

    /**
     * @notice 发起仲裁
     */
    function initiateArbitration(uint256 orderId) external payable;

    /**
     * @notice 强制清算
     */
    function forceLiquidate(uint256 orderId) external;

    // ==================== 查询功能 ====================

    function getOrder(uint256 orderId) external view returns (Order memory);
    function getQuotes(uint256 orderId) external view returns (Quote[] memory);
    function getBuyerOrders(address buyer) external view returns (uint256[] memory);
    function getSellerOrders(address seller) external view returns (uint256[] memory);
}

contracts/libraries/NSTTypes.sol.content:
// SPDX-License-Identifier: MIT
pragma solidity ^0.8.20;

/**
 * @title NSTTypes
 * @notice 数据类型定义 - NST Options MVP
 * @dev 定义所有合约共用的数据结构和枚举
 */

/**
 * @notice 订单方向
 */
enum Direction {
    Call,   // 看涨
    Put     // 看跌
}

/**
 * @notice 卖方类型
 */
enum SellerType {
    FreeSeller,         // 自由卖方
    SeatSeller,         // 席位卖方
    DesignatedSeller    // 指定卖方
}

/**
 * @notice 强平规则
 */
enum LiquidationRule {
    NoLiquidation,          // 无强平，到期结算
    ConsecutiveLimitUp,     // 连续涨停板强平（触板/封板）
    ConsecutiveDailyGain    // 连续单日涨幅≥X%强平
}

/**
 * @notice 订单状态
 */
enum OrderStatus {
    RFQ_CREATED,            // 询价已创建
    QUOTING,                // 报价中
    MATCHED,                // 已匹配，待喂价
    WAITING_INITIAL_FEED,   // 待期初喂价
    LIVE,                   // 持仓中
    WAITING_FINAL_FEED,     // 待期末喂价
    PENDING_SETTLEMENT,     // 待结算
    ARBITRATION,            // 仲裁中
    SETTLED,                // 已结算
    LIQUIDATED,             // 已强平
    CANCELLED               // 已取消
}

/**
 * @notice 报价状态
 */
enum QuoteStatus {
    Active,     // 有效
    Accepted,   // 已接受
    Rejected,   // 已拒绝
    Expired     // 已过期
}

/**
 * @notice 喂价类型
 */
enum FeedType {
    Initial,        // 期初喂价
    Dynamic,        // 动态保证金调整喂价
    Final,          // 期末喂价
    Arbitration     // 仲裁喂价
}

/**
 * @notice 喂价档位
 */
enum FeedTier {
    Tier_5_3,   // 5个喂价员，取3个有效
    Tier_7_5,   // 7个喂价员，取5个有效
    Tier_10_7   // 10个喂价员，取7个有效
}

/**
 * @notice 喂价规则
 */
enum FeedRule {
    NormalFeed,         // 正常喂价（市价）
    VolumeBasedFeed     // 跟量成交喂价（需真实成交量支持）
}

/**
 * @notice 订单结构体
 */
struct Order {
    // 基础信息
    uint256 orderId;
    address buyer;
    address seller;
    
    // 标的信息
    string underlyingName;      // 标的名称
    string underlyingCode;      // 标的代码
    string market;              // 市场
    string country;             // 国家
    string refPrice;            // 参考价格
    
    // 合约要素
    Direction direction;        // 看涨/看跌
    uint256 notionalUSDT;       // 名义本金
    uint256 strikePrice;        // 行权价
    uint256 expiryTimestamp;    // 到期时间
    
    // 费率与保证金
    uint256 premiumRate;        // 期权费率（基点）
    uint256 premiumAmount;      // 期权费金额
    uint256 initialMargin;      // 初始保证金
    uint256 currentMargin;      // 当前保证金
    uint256 minMarginRate;      // 最低保证金率（基点）
    
    // 平仓规则
    LiquidationRule liquidationRule;
    uint8 consecutiveDays;      // 连续天数
    uint8 dailyLimitPercent;    // 单日涨幅阈值
    uint8 exerciseDelay;        // T+X 行权延迟
    
    // 卖方类型
    SellerType sellerType;
    address designatedSeller;   // 指定卖方地址
    
    // 仲裁与追保配置
    uint256 arbitrationWindow;  // 仲裁窗口
    uint256 marginCallDeadline; // 追保截止时间
    
    // 分红调整
    bool dividendAdjustment;    // 是否调整行权价
    
    // 喂价规则
    FeedRule feedRule;          // 正常喂价/跟量成交喂价
    
    // 状态与时间
    OrderStatus status;
    uint256 createdAt;
    uint256 matchedAt;
    uint256 settledAt;
    uint256 lastFeedPrice;      // 最后一次喂价价格
}

/**
 * @notice 报价结构体
 */
struct Quote {
    uint256 quoteId;
    uint256 orderId;
    address seller;
    SellerType sellerType;
    
    uint256 premiumRate;        // 报价费率（基点）
    uint256 premiumAmount;      // 期权费金额
    uint256 marginRate;         // 保证金比例
    uint256 marginAmount;       // 保证金金额
    
    LiquidationRule liquidationRule;
    uint8 consecutiveDays;
    uint8 dailyLimitPercent;
    
    uint256 createdAt;
    uint256 expiresAt;          // 报价有效期
    QuoteStatus status;
}

/**
 * @notice 席位信息结构体
 */
struct Seat {
    address owner;
    uint256 depositAmount;      // 席位押金
    uint256 nstStaked;          // 质押的NST数量
    uint256 stakeStartTime;     // 质押开始时间
    uint256 currentExposure;    // 当前风险敞口
    uint256 maxExposure;        // 最大允许敞口
    bool isActive;
}

/**
 * @notice 喂价请求结构体
 */
struct FeedRequest {
    uint256 requestId;
    uint256 orderId;
    FeedType feedType;
    FeedTier tier;
    uint256 deadline;           // 喂价截止时间
    uint256 createdAt;
    uint256 totalFeeders;       // 需要的喂价员数量
    uint256 submittedCount;     // 已提交数量
    uint256 finalPrice;         // 最终价格
    bool finalized;             // 是否已完成
}

/**
 * @notice 用户积分结构体
 */
struct UserPoints {
    uint256 totalPoints;        // 累计积分
    uint256 claimedPoints;      // 已领取空投的积分
    uint256 availablePoints;    // 可用积分
    uint256 lastUpdateTime;     // 最后更新时间
}

contracts/vault/VaultManager.sol.content:
// SPDX-License-Identifier: MIT
pragma solidity ^0.8.20;

import "@openzeppelin/contracts/token/ERC20/IERC20.sol";
import "@openzeppelin/contracts/token/ERC20/utils/SafeERC20.sol";
import "@openzeppelin/contracts/access/AccessControl.sol";
import "@openzeppelin/contracts/utils/ReentrancyGuard.sol";
import "@openzeppelin/contracts/utils/Pausable.sol";
import "../core/Config.sol";

/**
 * @title VaultManager
 * @notice 资金池管理合约 - 资金调度与状态执行中枢
 * @dev 只接受授权的合约调用，不直接与用户交互
 */
contract VaultManager is AccessControl, ReentrancyGuard, Pausable {
    using SafeERC20 for IERC20;

    // ==================== 角色定义 ====================
    bytes32 public constant VAULT_OPERATOR_ROLE = keccak256("VAULT_OPERATOR_ROLE");

    // ==================== 状态变量 ====================
    Config public config;
    
    // 资金池余额
    mapping(address => uint256) public marginPoolBalance;       // 保证金池
    mapping(address => uint256) public profitPoolBalance;       // 生态利润池
    mapping(address => uint256) public lpPoolBalance;           // 代币LP池
    mapping(address => uint256) public interactPoolBalance;     // 合约交互池
    mapping(address => uint256) public donationPoolBalance;     // 捐赠节点池

    // 用户保证金余额
    mapping(address => mapping(address => uint256)) public userMarginBalance;  // user => token => balance

    // ==================== 事件 ====================
    event MarginDeposited(
        address indexed user,
        address indexed token,
        uint256 amount,
        uint256 timestamp
    );

    event MarginWithdrawn(
        address indexed user,
        address indexed token,
        uint256 amount,
        uint256 timestamp
    );

    event MarginTransferred(
        address indexed from,
        address indexed to,
        address indexed token,
        uint256 amount,
        string reason,
        uint256 timestamp
    );

    event FeeCollected(
        address indexed token,
        uint256 amount,
        string feeType,
        uint256 timestamp
    );

    event ProfitDistributed(
        address indexed token,
        uint256 amount,
        string poolType,
        uint256 timestamp
    );

    // ==================== 构造函数 ====================
    constructor(address _config, address _admin) {
        config = Config(_config);
        _grantRole(DEFAULT_ADMIN_ROLE, _admin);
        _grantRole(VAULT_OPERATOR_ROLE, _admin);
    }

    // ==================== 修改器 ====================
    modifier onlyOperator() {
        require(hasRole(VAULT_OPERATOR_ROLE, msg.sender), "VaultManager: caller is not operator");
        _;
    }

    // ==================== 保证金操作 ====================

    /**
     * @notice 存入保证金
     * @param _user 用户地址
     * @param _token 代币地址
     * @param _amount 金额
     */
    function depositMargin(
        address _user,
        address _token,
        uint256 _amount
    ) external onlyOperator nonReentrant whenNotPaused {
        require(_amount > 0, "VaultManager: amount must be greater than 0");
        
        IERC20(_token).safeTransferFrom(_user, address(this), _amount);
        userMarginBalance[_user][_token] += _amount;
        marginPoolBalance[_token] += _amount;

        emit MarginDeposited(_user, _token, _amount, block.timestamp);
    }

    /**
     * @notice 提取保证金
     * @param _user 用户地址
     * @param _token 代币地址
     * @param _amount 金额
     */
    function withdrawMargin(
        address _user,
        address _token,
        uint256 _amount
    ) external onlyOperator nonReentrant whenNotPaused {
        require(_amount > 0, "VaultManager: amount must be greater than 0");
        require(userMarginBalance[_user][_token] >= _amount, "VaultManager: insufficient balance");

        userMarginBalance[_user][_token] -= _amount;
        marginPoolBalance[_token] -= _amount;
        IERC20(_token).safeTransfer(_user, _amount);

        emit MarginWithdrawn(_user, _token, _amount, block.timestamp);
    }

    /**
     * @notice 内部转移保证金（订单结算时使用）
     * @param _from 发送方
     * @param _to 接收方
     * @param _token 代币地址
     * @param _amount 金额
     * @param _reason 转移原因
     */
    function transferMargin(
        address _from,
        address _to,
        address _token,
        uint256 _amount,
        string calldata _reason
    ) external onlyOperator nonReentrant whenNotPaused {
        require(userMarginBalance[_from][_token] >= _amount, "VaultManager: insufficient balance");

        userMarginBalance[_from][_token] -= _amount;
        userMarginBalance[_to][_token] += _amount;

        emit MarginTransferred(_from, _to, _token, _amount, _reason, block.timestamp);
    }

    // ==================== 手续费操作 ====================

    /**
     * @notice 收取手续费
     * @param _user 用户地址
     * @param _token 代币地址
     * @param _amount 金额
     * @param _feeType 费用类型
     */
    function collectFee(
        address _user,
        address _token,
        uint256 _amount,
        string calldata _feeType
    ) external onlyOperator nonReentrant whenNotPaused {
        require(_amount > 0, "VaultManager: amount must be greater than 0");

        IERC20(_token).safeTransferFrom(_user, address(this), _amount);
        profitPoolBalance[_token] += _amount;

        emit FeeCollected(_token, _amount, _feeType, block.timestamp);
    }

    /**
     * @notice 分配利润到各池子
     * @param _token 代币地址
     * @param _amount 总金额
     */
    function distributeProfits(
        address _token,
        uint256 _amount
    ) external onlyOperator nonReentrant whenNotPaused {
        require(profitPoolBalance[_token] >= _amount, "VaultManager: insufficient profit pool");

        profitPoolBalance[_token] -= _amount;

        // 按比例分配
        uint256 nodeReward = (_amount * config.nodeRewardShare()) / 10000;
        uint256 buyback = (_amount * config.tokenBuybackShare()) / 10000;
        uint256 lp = (_amount * config.lpPoolShare()) / 10000;
        // 剩余部分分配给团队、基金会、DAO、成长节点
        // 这里简化处理，实际需要转账到对应地址

        lpPoolBalance[_token] += lp;
        donationPoolBalance[_token] += nodeReward;

        emit ProfitDistributed(_token, _amount, "all", block.timestamp);
    }

    /**
     * @notice 转移喂价费用到喂价生态
     * @param _token 代币地址
     * @param _amount 金额
     * @param _feedProtocol 喂价协议地址
     */
    function transferToFeedProtocol(
        address _token,
        uint256 _amount,
        address _feedProtocol
    ) external onlyOperator nonReentrant whenNotPaused {
        require(interactPoolBalance[_token] >= _amount, "VaultManager: insufficient interact pool");
        interactPoolBalance[_token] -= _amount;
        IERC20(_token).safeTransfer(_feedProtocol, _amount);
    }

    // ==================== LP池操作 ====================

    /**
     * @notice 存入LP池
     */
    function depositToLPPool(
        address _token,
        uint256 _amount
    ) external onlyOperator nonReentrant whenNotPaused {
        require(_amount > 0, "VaultManager: amount must be greater than 0");
        IERC20(_token).safeTransferFrom(msg.sender, address(this), _amount);
        lpPoolBalance[_token] += _amount;
        
        emit ProfitDistributed(_token, _amount, "lp_deposit", block.timestamp);
    }

    /**
     * @notice 从LP池提取
     */
    function withdrawFromLPPool(
        address _token,
        uint256 _amount,
        address _recipient
    ) external onlyOperator nonReentrant whenNotPaused {
        require(lpPoolBalance[_token] >= _amount, "VaultManager: insufficient LP pool");
        lpPoolBalance[_token] -= _amount;
        IERC20(_token).safeTransfer(_recipient, _amount);
        
        emit ProfitDistributed(_token, _amount, "lp_withdraw", block.timestamp);
    }

    // ==================== 交互池操作 ====================

    /**
     * @notice 存入交互池（用于支付合约交互费用）
     */
    function depositToInteractPool(
        address _token,
        uint256 _amount
    ) external onlyOperator nonReentrant whenNotPaused {
        require(_amount > 0, "VaultManager: amount must be greater than 0");
        IERC20(_token).safeTransferFrom(msg.sender, address(this), _amount);
        interactPoolBalance[_token] += _amount;
        
        emit ProfitDistributed(_token, _amount, "interact_deposit", block.timestamp);
    }

    /**
     * @notice 从交互池提取
     */
    function withdrawFromInteractPool(
        address _token,
        uint256 _amount,
        address _recipient
    ) external onlyOperator nonReentrant whenNotPaused {
        require(interactPoolBalance[_token] >= _amount, "VaultManager: insufficient interact pool");
        interactPoolBalance[_token] -= _amount;
        IERC20(_token).safeTransfer(_recipient, _amount);
        
        emit ProfitDistributed(_token, _amount, "interact_withdraw", block.timestamp);
    }

    // ==================== 捐赠节点池操作 ====================

    /**
     * @notice 存入捐赠节点池
     */
    function depositToDonationPool(
        address _token,
        uint256 _amount
    ) external onlyOperator nonReentrant whenNotPaused {
        require(_amount > 0, "VaultManager: amount must be greater than 0");
        IERC20(_token).safeTransferFrom(msg.sender, address(this), _amount);
        donationPoolBalance[_token] += _amount;
        
        emit ProfitDistributed(_token, _amount, "donation_deposit", block.timestamp);
    }

    /**
     * @notice 从捐赠节点池提取（用于节点奖励分配）
     */
    function withdrawFromDonationPool(
        address _token,
        uint256 _amount,
        address _recipient
    ) external onlyOperator nonReentrant whenNotPaused {
        require(donationPoolBalance[_token] >= _amount, "VaultManager: insufficient donation pool");
        donationPoolBalance[_token] -= _amount;
        IERC20(_token).safeTransfer(_recipient, _amount);
        
        emit ProfitDistributed(_token, _amount, "donation_withdraw", block.timestamp);
    }

    /**
     * @notice 批量分配节点奖励
     * @param _token 代币地址
     * @param _recipients 接收者列表
     * @param _amounts 金额列表
     */
    function batchDistributeNodeRewards(
        address _token,
        address[] calldata _recipients,
        uint256[] calldata _amounts
    ) external onlyOperator nonReentrant whenNotPaused {
        require(_recipients.length == _amounts.length, "VaultManager: length mismatch");
        
        uint256 totalAmount = 0;
        for (uint256 i = 0; i < _amounts.length; i++) {
            totalAmount += _amounts[i];
        }
        require(donationPoolBalance[_token] >= totalAmount, "VaultManager: insufficient donation pool");
        
        donationPoolBalance[_token] -= totalAmount;
        
        for (uint256 i = 0; i < _recipients.length; i++) {
            IERC20(_token).safeTransfer(_recipients[i], _amounts[i]);
        }
        
        emit ProfitDistributed(_token, totalAmount, "node_rewards_batch", block.timestamp);
    }

    // ==================== 利润池高级操作 ====================

    /**
     * @notice 从利润池转入其他子池
     * @param _token 代币地址
     * @param _lpAmount LP池金额
     * @param _interactAmount 交互池金额
     * @param _donationAmount 捐赠池金额
     */
    function allocateProfitToSubPools(
        address _token,
        uint256 _lpAmount,
        uint256 _interactAmount,
        uint256 _donationAmount
    ) external onlyOperator nonReentrant whenNotPaused {
        uint256 totalAmount = _lpAmount + _interactAmount + _donationAmount;
        require(profitPoolBalance[_token] >= totalAmount, "VaultManager: insufficient profit pool");
        
        profitPoolBalance[_token] -= totalAmount;
        lpPoolBalance[_token] += _lpAmount;
        interactPoolBalance[_token] += _interactAmount;
        donationPoolBalance[_token] += _donationAmount;
        
        emit ProfitDistributed(_token, totalAmount, "profit_allocation", block.timestamp);
    }

    // ==================== 查询函数 ====================

    /**
     * @notice 查询用户保证金余额
     */
    function getUserMarginBalance(
        address _user,
        address _token
    ) external view returns (uint256) {
        return userMarginBalance[_user][_token];
    }

    /**
     * @notice 查询总保证金池余额
     */
    function getTotalMarginPool(address _token) external view returns (uint256) {
        return marginPoolBalance[_token];
    }

    /**
     * @notice 查询利润池余额
     */
    function getProfitPoolBalance(address _token) external view returns (uint256) {
        return profitPoolBalance[_token];
    }

    // ==================== 管理函数 ====================

    /**
     * @notice 更新 Config 地址
     */
    function setConfig(address _config) external onlyRole(DEFAULT_ADMIN_ROLE) {
        config = Config(_config);
    }

    /**
     * @notice 授权操作者角色
     */
    function grantOperatorRole(address _operator) external onlyRole(DEFAULT_ADMIN_ROLE) {
        grantRole(VAULT_OPERATOR_ROLE, _operator);
    }

    /**
     * @notice 暂停合约
     */
    function pause() external onlyRole(DEFAULT_ADMIN_ROLE) {
        _pause();
    }

    /**
     * @notice 恢复合约
     */
    function unpause() external onlyRole(DEFAULT_ADMIN_ROLE) {
        _unpause();
    }
}

